/**
 * Additive, idempotent government scheme seed (batch 2) for Paisa Reality.
 *
 * Adds more real, currently active central schemes and extends state coverage to
 * every state and union territory. Safe to run on the live database: it only
 * performs INSERT ... ON CONFLICT (slug) DO UPDATE inside a transaction. No
 * deletes, no resets. Existing rows are only refreshed when slugs match.
 *
 * Run:
 *   npm run db:seed-schemes-expansion-2
 *
 * Accuracy note: figures are kept general where a precise current amount was not
 * certain. Every scheme links to its official source for verification.
 */
import { Pool } from 'pg';

type Gender = 'all' | 'male' | 'female' | 'transgender';
type Area = 'all' | 'urban' | 'rural';

interface SchemeSeed {
  slug: string;
  name: string;
  name_hi: string | null;
  category: string;
  level: 'central' | 'state';
  ministry: string | null;
  description: string;
  benefit_summary: string;
  benefit_amount_max: number | null;
  apply_url: string | null;
  official_url: string | null;
  min_age: number | null;
  max_age: number | null;
  gender: Gender;
  states: string[];
  categories: string[];
  max_income: number | null;
  occupations: string[];
  education_min: string | null;
  area: Area;
  bpl_required: boolean;
  minority_only: boolean;
  disability_only: boolean;
  how_to_apply: string;
  documents_required: string[];
  meta_title: string | null;
  meta_description: string | null;
  source_url: string;
}

type SchemeInput =
  Pick<SchemeSeed, 'slug' | 'name' | 'category' | 'level' | 'description' | 'benefit_summary' | 'official_url'>
  & Partial<SchemeSeed>;

function S(o: SchemeInput): SchemeSeed {
  return {
    name_hi: null, ministry: null, benefit_amount_max: null, apply_url: null,
    min_age: null, max_age: null, gender: 'all', states: ['all'], categories: ['all'],
    max_income: null, occupations: ['all'], education_min: null, area: 'all',
    bpl_required: false, minority_only: false, disability_only: false,
    how_to_apply: '', documents_required: [], meta_title: null, meta_description: null,
    source_url: o.official_url ?? '',
    ...o,
  };
}

