const COLUMNS = [
  'slug', 'name', 'name_hi', 'category', 'level', 'ministry', 'description', 'benefit_summary',
  'benefit_amount_max', 'apply_url', 'official_url', 'min_age', 'max_age', 'gender',
  'states', 'categories', 'max_income', 'occupations', 'education_min', 'area',
  'bpl_required', 'minority_only', 'disability_only', 'how_to_apply', 'documents_required',
  'meta_title', 'meta_description', 'source_url',
];

const UPDATE_SET = COLUMNS.filter((c) => c !== 'slug')
  .map((c) => `${c}=EXCLUDED.${c}`)
  .concat(['last_verified=CURRENT_DATE', 'is_active=true'])
  .join(', ');

const JSONB_COLUMNS = new Set(['states', 'categories', 'occupations', 'documents_required']);
const PLACEHOLDERS = COLUMNS.map((c, i) => (JSONB_COLUMNS.has(c) ? `$${i + 1}::jsonb` : `$${i + 1}`)).join(', ');
const INSERT_SQL =
  `INSERT INTO schemes (${COLUMNS.join(', ')}, last_verified, is_active) ` +
  `VALUES (${PLACEHOLDERS}, CURRENT_DATE, true) ` +
  `ON CONFLICT (slug) DO UPDATE SET ${UPDATE_SET} ` +
  `RETURNING (xmax = 0) AS inserted`;

function buildValues(s: SchemeSeed): unknown[] {
  return [
    s.slug, s.name, s.name_hi, s.category, s.level, s.ministry, s.description, s.benefit_summary,
    s.benefit_amount_max, s.apply_url, s.official_url, s.min_age, s.max_age, s.gender,
    JSON.stringify(s.states), JSON.stringify(s.categories), s.max_income, JSON.stringify(s.occupations),
    s.education_min, s.area, s.bpl_required, s.minority_only, s.disability_only, s.how_to_apply,
    JSON.stringify(s.documents_required), s.meta_title, s.meta_description, s.source_url,
  ];
}

const VALID_GENDER = new Set(['all', 'male', 'female', 'transgender']);
const VALID_AREA = new Set(['all', 'urban', 'rural']);

function validate(): void {
  const seen = new Set<string>();
  for (const s of SCHEMES) {
    if (seen.has(s.slug)) throw new Error(`Duplicate slug in dataset: ${s.slug}`);
    seen.add(s.slug);
    if (!VALID_GENDER.has(s.gender)) throw new Error(`Invalid gender for ${s.slug}`);
    if (!VALID_AREA.has(s.area)) throw new Error(`Invalid area for ${s.slug}`);
    if (!s.name || !s.category || !s.description || !s.benefit_summary) throw new Error(`Missing field for ${s.slug}`);
  }
}

async function main(): Promise<void> {
  const connectionString = process.env.DATABASE_URL;
  if (!connectionString) {
    console.error('DATABASE_URL is not set. Aborting without any database change.');
    process.exit(1);
  }
  validate();
  console.log(`Dataset prepared: ${SCHEMES.length} schemes (additive, idempotent upsert by slug).`);

  const pool = new Pool({ connectionString, max: 4 });
  const client = await pool.connect();
  let inserted = 0;
  let updated = 0;
  try {
    await client.query('BEGIN');
    for (const s of SCHEMES) {
      const res = await client.query(INSERT_SQL, buildValues(s));
      const row = res.rows[0] as { inserted?: boolean } | undefined;
      if (row && row.inserted) inserted += 1;
      else updated += 1;
    }
    await client.query('COMMIT');
    const totals = await client.query('SELECT count(*)::int AS total, count(*) FILTER (WHERE is_active)::int AS active FROM schemes');
    console.log(`Upsert complete. Newly inserted: ${inserted}. Refreshed existing: ${updated}.`);
    console.log(`Schemes table now: total ${totals.rows[0].total}, active ${totals.rows[0].active}.`);
  } catch (e) {
    await client.query('ROLLBACK');
    throw e;
  } finally {
    client.release();
    await pool.end();
  }
}

main().catch((e: unknown) => {
  console.error('FATAL:', e instanceof Error ? e.message : e);
  process.exit(1);
});
